import React, { useState, useMemo } from 'react';
import { Tag } from '../types';
import { Search, Plus, Frown, Smile, Check } from 'lucide-react';

interface TagSectionProps {
  title: string;
  emoji: 'happy' | 'sad';
  tags: Tag[];
  selectedTagIds: string[];
  onToggleTag: (id: string) => void;
  searchPlaceholder?: string;
}

const TagSection: React.FC<TagSectionProps> = ({
  title,
  emoji,
  tags,
  selectedTagIds,
  onToggleTag,
  searchPlaceholder = "Search tag or select from below"
}) => {
  const [searchQuery, setSearchQuery] = useState('');

  const filteredTags = useMemo(() => {
    return tags.filter(tag => 
      tag.label.toLowerCase().includes(searchQuery.toLowerCase())
    );
  }, [tags, searchQuery]);

  // Helper to highlight matching text
  const renderLabel = (label: string) => {
    if (!searchQuery) return label;
    // Escape regex special characters
    const escapedQuery = searchQuery.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    const regex = new RegExp(`(${escapedQuery})`, 'gi');
    const parts = label.split(regex);

    return parts.map((part, index) => 
      regex.test(part) ? (
        <span key={index} className="bg-yellow-200 text-gray-900 font-extrabold px-0.5 rounded-[2px]">{part}</span>
      ) : (
        <span key={index}>{part}</span>
      )
    );
  };

  return (
    <div className="bg-white p-5 rounded-xl shadow-sm mb-4 transition-all duration-300 ease-in-out">
      <div className="flex items-center gap-2 mb-4">
        <h3 className="text-gray-900 font-bold text-lg">{title}</h3>
        {emoji === 'sad' ? (
          <Frown className="w-6 h-6 text-orange-400 stroke-[1.5]" />
        ) : (
          <Smile className="w-6 h-6 text-orange-400 stroke-[1.5]" />
        )}
      </div>

      <div className="relative mb-4 group">
        <Search className={`absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 transition-colors duration-300 ${searchQuery ? 'text-orange-500' : 'text-gray-400'}`} />
        <input
          type="text"
          placeholder={searchPlaceholder}
          value={searchQuery}
          onChange={(e) => setSearchQuery(e.target.value)}
          className="w-full bg-gray-50 border border-gray-100 text-sm py-3 pl-10 pr-4 rounded-xl placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-orange-100 focus:bg-white focus:border-orange-200 transition-all duration-300"
        />
      </div>

      <div className="flex flex-wrap gap-2.5 min-h-[40px]">
        {filteredTags.map((tag) => {
          const isSelected = selectedTagIds.includes(tag.id);
          return (
            <button
              key={tag.id}
              onClick={() => onToggleTag(tag.id)}
              className={`px-4 py-2.5 rounded-full text-xs font-bold transition-all duration-300 flex items-center gap-1.5 border ${
                isSelected
                  ? 'bg-[#F97316] border-[#F97316] text-white shadow-md shadow-orange-100 transform scale-105'
                  : 'bg-white border-gray-200 text-gray-500 hover:border-gray-300 hover:bg-gray-50'
              }`}
            >
              {isSelected && <Check className="w-3.5 h-3.5" strokeWidth={3} />}
              <span>{renderLabel(tag.label)}</span>
            </button>
          );
        })}
        {filteredTags.length === 0 && searchQuery && (
          <button 
            onClick={() => console.log('New tag added:', searchQuery)}
            className="flex items-center gap-1 px-4 py-2.5 rounded-full text-xs font-medium bg-gray-50 text-gray-400 border border-dashed border-gray-300 hover:bg-gray-100 transition-colors"
          >
            <Plus className="w-3 h-3" /> Add "{searchQuery}"
          </button>
        )}
      </div>
    </div>
  );
};

export default TagSection;

import React from 'react';
import { ReviewCategory } from '../types';
import { Star, ShoppingBag, Truck } from 'lucide-react';

interface RatingCardProps {
  rating: number;
  category: ReviewCategory;
  onRatingChange: (rating: number) => void;
  onCategoryChange: (category: ReviewCategory) => void;
}

const RatingCard: React.FC<RatingCardProps> = ({
  rating,
  category,
  onRatingChange,
  onCategoryChange,
}) => {
  const renderStarRow = (starCount: number, widthPercent: string) => {
    const isSelected = rating === starCount;

    return (
      <button
        key={starCount}
        onClick={() => onRatingChange(starCount)}
        className={`w-full flex items-center gap-3 py-2 group transition-all duration-300 ease-out ${
          isSelected ? 'scale-105' : 'hover:scale-[1.02]'
        }`}
      >
        <div className="w-20 text-right flex items-center justify-end gap-1.5">
          <span className={`text-white transition-all duration-300 ${
            isSelected ? 'text-sm font-bold drop-shadow-md' : 'text-xs font-medium opacity-75'
          }`}>
            {starCount} Star{starCount > 1 ? 's' : ''}
          </span>
          <Star 
             className={`w-3.5 h-3.5 text-white transition-all duration-300 ${
               isSelected ? 'opacity-100 fill-white rotate-0' : 'opacity-0 -rotate-90 w-0'
             }`}
          />
        </div>

        <div className={`flex-1 rounded-full overflow-hidden transition-all duration-300 border border-white/10 ${
            isSelected ? 'bg-white/20 h-5 shadow-inner' : 'bg-white/10 h-3 group-hover:bg-white/15'
        }`}>
          <div
            className={`h-full rounded-full transition-all duration-500 ease-out relative ${
              isSelected ? 'opacity-100 shadow-[0_2px_4px_rgba(0,0,0,0.1)]' : 'opacity-50 group-hover:opacity-70'
            }`}
            style={{ 
              width: widthPercent,
              backgroundColor: '#F97316'
            }}
          >
             {isSelected && (
                <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/20 to-transparent" />
             )}
          </div>
        </div>
      </button>
    );
  };

  return (
    <div className="bg-[#3B82F6] rounded-xl p-5 shadow-lg shadow-blue-200 mb-4 overflow-hidden relative transition-colors duration-500">
      {/* Decorative background element */}
      <div className="absolute -top-10 -right-10 w-32 h-32 bg-white/5 rounded-full blur-2xl pointer-events-none"></div>
      <div className="absolute -bottom-10 -left-10 w-32 h-32 bg-white/5 rounded-full blur-2xl pointer-events-none"></div>

      <div className="flex flex-col items-center mb-6 relative z-10">
        <h2 className="text-white text-lg font-bold mb-5 tracking-tight">Rate your experience</h2>

        {/* Custom Toggle */}
        <div className="flex items-center p-1.5 bg-black/20 rounded-full backdrop-blur-md border border-white/10 relative">
           <button 
             onClick={() => onCategoryChange('Shopping')}
             className={`flex items-center gap-2 px-5 py-2.5 rounded-full transition-all duration-300 ease-out active:scale-95 ${
               category === 'Shopping' 
                 ? 'bg-white text-[#3B82F6] shadow-lg scale-100' 
                 : 'text-white/80 hover:bg-white/10 hover:text-white'
             }`}
           >
              <ShoppingBag className={`w-4 h-4 ${category === 'Shopping' ? 'fill-[#3B82F6]/20' : ''}`} strokeWidth={2.5} />
              <span className="text-xs font-bold tracking-wide">
                Shopping
              </span>
           </button>

           <button 
             onClick={() => onCategoryChange('Delivery')}
             className={`flex items-center gap-2 px-5 py-2.5 rounded-full transition-all duration-300 ease-out active:scale-95 ${
               category === 'Delivery' 
                 ? 'bg-white text-[#3B82F6] shadow-lg scale-100' 
                 : 'text-white/80 hover:bg-white/10 hover:text-white'
             }`}
           >
              <Truck className={`w-4 h-4 ${category === 'Delivery' ? 'fill-[#3B82F6]/20' : ''}`} strokeWidth={2.5} />
              <span className="text-xs font-bold tracking-wide">
                Delivery
              </span>
           </button>
        </div>
      </div>

      <div className="space-y-1 relative z-10">
        {renderStarRow(5, '100%')}
        {renderStarRow(4, '80%')}
        {renderStarRow(3, '60%')}
        {renderStarRow(2, '40%')}
        {renderStarRow(1, '20%')}
      </div>
    </div>
  );
};

export default RatingCard;
